from flask import Flask, jsonify, request
from pymemcache.client.base import Client
import json
import time

app = Flask(__name__)
memcached = Client(('localhost', 11211))

# Mock database function
def get_user_from_db(user_id):
    # Simulate database delay
    time.sleep(0.1)
    return {"id": user_id, "name": f"User {user_id}", "email": f"user{user_id}@example.com"}

# Cache decorator for database queries
def cache_db_query(ttl=300):
    def decorator(func):
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"db:{func.__name__}:{hash(str(args) + str(kwargs))}"
            
            # Try to get from cache
            cached_result = memcached.get(cache_key)
            if cached_result:
                return json.loads(cached_result)
            
            # If not in cache, execute function and cache result
            result = func(*args, **kwargs)
            memcached.set(cache_key, json.dumps(result), expire=ttl)
            return result
        return wrapper
    return decorator

# Cache decorator for API responses
def cache_api_response(ttl=60):
    def decorator(func):
        def wrapper(*args, **kwargs):
            # Create cache key
            cache_key = f"api:{request.endpoint}:{hash(str(request.args) + str(request.get_json()) + str(args) + str(kwargs))}"
            
            # Try to get from cache
            cached_result = memcached.get(cache_key)
            if cached_result:
                return jsonify(json.loads(cached_result))
            
            # If not in cache, execute function and cache result
            result = func(*args, **kwargs)
            memcached.set(cache_key, json.dumps(result.get_json()), expire=ttl)
            return result
        return wrapper
    return decorator

# Example database cached endpoint
@app.route('/user/<int:user_id>')
@cache_db_query(ttl=300)
def get_user(user_id):
    user_data = get_user_from_db(user_id)
    return jsonify(user_data)

# Example API cached endpoint
@app.route('/api/data')
@cache_api_response(ttl=60)
def get_api_data():
    data = {"message": "Hello World", "timestamp": time.time()}
    return jsonify(data)

# Manual cache set/get example
@app.route('/cache/set/<key>/<value>')
def cache_set(key, value):
    memcached.set(key, value, expire=300)
    return jsonify({"status": "cached"})

@app.route('/cache/get/<key>')
def cache_get(key):
    value = memcached.get(key)
    if value:
        return jsonify({"key": key, "value": value.decode('utf-8')})
    return jsonify({"error": "Key not found"})

# Clear cache endpoint
@app.route('/cache/clear')
def clear_cache():
    memcached.flush_all()
    return jsonify({"status": "cache cleared"})

